import { useEffect, useState } from "react";
import { fetchStats } from "../api";

export default function StatsTab() {
  const [stats,   setStats]   = useState(null);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState(null);

  useEffect(() => {
    fetchStats()
      .then(setStats)
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="tab-container"><p style={{color:"var(--color-text-secondary)"}}>Loading statistics…</p></div>;
  if (error)   return <div className="tab-container"><div className="error-box">⚠ {error} — make sure Flask is running and stats JSON files exist</div></div>;
  if (!stats?.summary) return <div className="tab-container"><p style={{color:"var(--color-text-secondary)"}}>No stats data found. Run evaluate.py first.</p></div>;

  const summary  = stats.summary;
  const tests    = stats.tests;
  const unc      = stats.uncertainty;

  const correct    = summary.filter(d => d.correct).length;
  const total      = summary.length;
  const cleanCount = summary.filter(d => d.predicted === "Clean").length;
  const dirtyCount = summary.filter(d => d.predicted === "Dirty").length;

  // Calibration bins
  const binDefs = [
    { label:"0.5–0.6", lo:0.5, hi:0.6 },
    { label:"0.6–0.7", lo:0.6, hi:0.7 },
    { label:"0.7–0.8", lo:0.7, hi:0.8 },
    { label:"0.8–0.9", lo:0.8, hi:0.91 },
  ];
  const calBins = binDefs.map(b => {
    const inBin = summary.filter(d => d.confidence >= b.lo && d.confidence < b.hi);
    const acc   = inBin.length ? Math.round(inBin.filter(d=>d.correct).length/inBin.length*100) : 0;
    return { ...b, count: inBin.length, acc };
  });
  const maxAcc = 100;

  // Uncertainty sorted
  const uncSorted = unc
    ? [...unc].sort((a,b) => a.uncertainty_std - b.uncertainty_std)
    : [];
  const maxUnc = uncSorted.length ? uncSorted[uncSorted.length-1].uncertainty_std : 0.15;

  return (
    <div className="tab-container">
      <h2 className="tab-title">Model statistics</h2>

      {/* Metric cards */}
      <div className="cards-row">
        {[
          { label:"Accuracy",    value:`${(correct/total*100).toFixed(1)}%` },
          { label:"ROC-AUC",     value:"0.8997" },
          { label:"Dirty F1",    value:"85.71%" },
          { label:"Test images", value:total },
        ].map(c => (
          <div key={c.label} className="stat-card">
            <div className="stat-label">{c.label}</div>
            <div className="stat-value">{c.value}</div>
          </div>
        ))}
      </div>

      {/* Statistical tests */}
      {tests && (
        <div className="section">
          <h3 className="section-title">Statistical tests</h3>
          <div className="cards-row">
            <div className="test-card pass">
              <div className="test-name">Binomial test</div>
              <div className="test-stat">p = {tests.binomial_test.p_value}</div>
              <div className="test-verdict">Significantly better than chance ✓</div>
            </div>
            <div className="test-card pass">
              <div className="test-name">McNemar's test</div>
              <div className="test-stat">p = {tests.mcnemar_test.p_value}</div>
              <div className="test-verdict">Significantly better than baseline ✓</div>
            </div>
            <div className="test-card info">
              <div className="test-name">Bootstrap 95% CI</div>
              <div className="test-stat">
                [{(tests.bootstrap_ci.accuracy.ci_low*100).toFixed(1)}% –{" "}
                 {(tests.bootstrap_ci.accuracy.ci_high*100).toFixed(1)}%]
              </div>
              <div className="test-verdict">Accuracy confidence interval</div>
            </div>
          </div>
        </div>
      )}

      {/* Charts row */}
      <div className="charts-row">

        {/* Prediction pie — pure CSS/HTML */}
        <div className="chart-card">
          <h3 className="chart-title">Prediction distribution</h3>
          <div style={{display:"flex",alignItems:"center",gap:"2rem",padding:"1rem 0"}}>
            <div style={{position:"relative",width:120,height:120,flexShrink:0}}>
              <svg viewBox="0 0 36 36" style={{transform:"rotate(-90deg)",width:120,height:120}}>
                <circle cx="18" cy="18" r="15.9" fill="none" stroke="var(--color-border-tertiary)" strokeWidth="3"/>
                <circle cx="18" cy="18" r="15.9" fill="none" stroke="#4ade80" strokeWidth="3"
                  strokeDasharray={`${(cleanCount/total)*100} ${100-(cleanCount/total)*100}`}
                  strokeDashoffset="0"/>
                <circle cx="18" cy="18" r="15.9" fill="none" stroke="#f87171" strokeWidth="3"
                  strokeDasharray={`${(dirtyCount/total)*100} ${100-(dirtyCount/total)*100}`}
                  strokeDashoffset={`${-(cleanCount/total)*100}`}/>
              </svg>
              <div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",
                textAlign:"center",fontSize:13,fontWeight:500,color:"var(--color-text-primary)"}}>
                {total}
              </div>
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:10}}>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:12,height:12,borderRadius:2,background:"#4ade80"}}/>
                <span style={{fontSize:13,color:"var(--color-text-secondary)"}}>Clean — {cleanCount}</span>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:12,height:12,borderRadius:2,background:"#f87171"}}/>
                <span style={{fontSize:13,color:"var(--color-text-secondary)"}}>Dirty — {dirtyCount}</span>
              </div>
              <div style={{fontSize:12,color:"var(--color-text-secondary)",marginTop:4}}>
                Accuracy: {(correct/total*100).toFixed(1)}%
              </div>
            </div>
          </div>
        </div>

        {/* Calibration bar chart — pure HTML */}
        <div className="chart-card">
          <h3 className="chart-title">Calibration: confidence vs accuracy</h3>
          <div style={{display:"flex",flexDirection:"column",gap:8,padding:"0.5rem 0"}}>
            {calBins.map(b => (
              <div key={b.label} style={{display:"flex",alignItems:"center",gap:8}}>
                <span style={{fontSize:11,color:"var(--color-text-secondary)",width:60,flexShrink:0}}>{b.label}</span>
                <div style={{flex:1,display:"flex",flexDirection:"column",gap:3}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{height:14,width:`${b.acc}%`,background:"#4ade80",borderRadius:2,minWidth:2,transition:"width 0.3s"}}/>
                    <span style={{fontSize:11,color:"var(--color-text-secondary)"}}>{b.acc}%</span>
                  </div>
                </div>
                <span style={{fontSize:11,color:"var(--color-text-secondary)",width:30,textAlign:"right"}}>n={b.count}</span>
              </div>
            ))}
          </div>
          <div style={{display:"flex",gap:12,marginTop:8}}>
            <div style={{display:"flex",alignItems:"center",gap:6}}>
              <div style={{width:10,height:10,borderRadius:2,background:"#4ade80"}}/>
              <span style={{fontSize:11,color:"var(--color-text-secondary)"}}>Accuracy %</span>
            </div>
          </div>
        </div>
      </div>

      {/* Uncertainty strip */}
      {uncSorted.length > 0 && (
        <div className="chart-card full-width">
          <h3 className="chart-title">Per-image uncertainty (sorted, MC Dropout std)</h3>
          <div style={{display:"flex",flexDirection:"column",gap:3,padding:"0.5rem 0"}}>
            {uncSorted.map((d,i) => (
              <div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{
                  height:10,
                  width:`${(d.uncertainty_std/0.15)*100}%`,
                  background: d.correct ? "#4ade80" : "#f87171",
                  borderRadius:2,
                  minWidth:2,
                  transition:"width 0.3s"
                }}/>
                <span style={{fontSize:10,color:"var(--color-text-secondary)"}}>{d.uncertainty_std.toFixed(3)}</span>
              </div>
            ))}
          </div>
          <div style={{display:"flex",gap:16,marginTop:8}}>
            <div style={{display:"flex",alignItems:"center",gap:6}}>
              <div style={{width:10,height:10,borderRadius:2,background:"#4ade80"}}/>
              <span style={{fontSize:11,color:"var(--color-text-secondary)"}}>Correct</span>
            </div>
            <div style={{display:"flex",alignItems:"center",gap:6}}>
              <div style={{width:10,height:10,borderRadius:2,background:"#f87171"}}/>
              <span style={{fontSize:11,color:"var(--color-text-secondary)"}}>Wrong</span>
            </div>
            <span style={{fontSize:11,color:"var(--color-text-secondary)"}}>Bar width = uncertainty (max 0.15 threshold)</span>
          </div>
        </div>
      )}
    </div>
  );
}
